import { GoogleGenAI } from "@google/genai";

export class RevenueService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  /**
   * Generates hyper-personalized outreach based on prospect data.
   */
  async generateOutreach(prospect: { company: string, contact: string, pain: string }) {
    const prompt = `
      Act as a world-class B2B Sales Engineer.
      Company: ${prospect.company}
      Contact: ${prospect.contact}
      Identified Pain Point: ${prospect.pain}

      Objective: Write a short, "punchy" cold email (max 100 words) proposing an AI-Agent automation that solves their specific pain.
      Constraints:
      1. No fluff.
      2. No "I hope you're well".
      3. Focus on ROI/Time saved.
      4. End with a specific call to action.
      5. Tone: Brutally honest, high status, technical peer.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          temperature: 0.7,
          topP: 0.9,
        }
      });
      return response.text || "Failed to generate outreach.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Critical failure in content generation.";
    }
  }

  /**
   * Analyzes potential pivot vs double-down based on input metrics.
   */
  async analyzeStrategy(metrics: { outreach: number, replies: number, bookings: number }) {
    const prompt = `
      Act as RevenueArchitect-AI. Analyze these 14-day validation metrics:
      - Outreach Sent: ${metrics.outreach}
      - Positive Replies: ${metrics.replies}
      - Demo Bookings: ${metrics.bookings}

      Output exactly one recommendation: "DOUBLE DOWN" or "PIVOT".
      Provide a 2-sentence rationale based strictly on conversion rates (Expect >3% reply rate, >1% booking rate).
    `;

    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  }
}

import React, { useState, useEffect } from 'react';
