import React, { useEffect, useRef } from 'react';

interface Log {
  id: string;
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error' | 'agent';
}

interface AgentConsoleProps {
  logs: Log[];
  isWorking: boolean;
}

const AgentConsole: React.FC<AgentConsoleProps> = ({ logs, isWorking }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs]);

  return (
    <div className="bg-[#050505] border border-[#222] rounded-xl overflow-hidden flex flex-col h-full shadow-2xl">
      <div className="bg-[#111] px-4 py-2 border-b border-[#222] flex justify-between items-center">
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-red-500/50" />
          <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/50" />
          <div className="w-2.5 h-2.5 rounded-full bg-green-500/50" />
        </div>
        <span className="text-[10px] mono text-gray-500 font-bold tracking-widest uppercase">
          Agent Runtime v4.0.2 {isWorking && '• RUNNING'}
        </span>
      </div>
      <div 
        ref={scrollRef}
        className="flex-1 p-4 mono text-[11px] overflow-y-auto space-y-1 bg-[radial-gradient(circle_at_center,_#111_0%,_#050505_100%)]"
      >
        {logs.length === 0 && (
          <div className="text-gray-700 italic">Initialize agent to begin revenue sequence...</div>
        )}
        {logs.map((log) => (
          <div key={log.id} className="flex gap-3 leading-relaxed">
            <span className="text-gray-600 shrink-0">[{log.timestamp}]</span>
            <span className={`
              ${log.type === 'success' ? 'text-green-500' : ''}
              ${log.type === 'warning' ? 'text-yellow-500' : ''}
              ${log.type === 'error' ? 'text-red-500' : ''}
              ${log.type === 'agent' ? 'text-blue-400 font-bold' : 'text-gray-400'}
            `}>
              <span className="opacity-50 mr-2">{log.type === 'agent' ? '🤖' : '>'}</span>
              {log.message}
            </span>
          </div>
        ))}
        {isWorking && (
          <div className="flex gap-2 text-yellow-500 animate-pulse">
            <span className="opacity-50">[{new Date().toLocaleTimeString()}]</span>
            <span>Agent is thinking...</span>
          </div>
        )}
      </div>
    </div>
  );
};

