import React, { useState, useEffect, useCallback } from 'react';
import { ICONS, REVENUE_GOAL } from './constants';
import Dashboard from './components/Dashboard';
import StrategyRoom from './components/StrategyRoom';
import LeadGenerator from './components/LeadGenerator';
import Checklist from './components/Checklist';
import AgentConsole from './components/AgentConsole';
import { RevenueService } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'strategy' | 'leads' | 'checklist'>('dashboard');
  const [currentRevenue, setCurrentRevenue] = useState(0);
  const [isAgentActive, setIsAgentActive] = useState(false);
  const [logs, setLogs] = useState<any[]>([]);
  const [stats, setStats] = useState({ leads: 142, sent: 89, replies: 4, bookings: 1 });

  const revService = new RevenueService();

  const addLog = (message: string, type: 'info' | 'success' | 'warning' | 'error' | 'agent' = 'info') => {
    setLogs(prev => [...prev, {
      id: Math.random().toString(36),
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    }].slice(-50));
  };

  const runAgentCycle = useCallback(async () => {
    if (!isAgentActive) return;

    try {
      const decision = await revService.decideNextAction({
        leads: stats.leads,
        emailsSent: stats.sent,
        replies: stats.replies,
        profit: currentRevenue
      });

      addLog(`AGENT REASONING: ${decision.reasoning}`, 'agent');
      addLog(decision.logMessage, 'info');

      // Simulate the action outcome
      setTimeout(() => {
        switch (decision.action) {
          case 'SCRAPE_LEADS':
            const newLeads = Math.floor(Math.random() * 15) + 5;
            setStats(s => ({ ...s, leads: s.leads + newLeads }));
            addLog(`Discovered ${newLeads} new high-intent prospects via LinkedIn Sales Nav.`, 'success');
            break;
          case 'SEND_EMAILS':
            const sentCount = Math.min(stats.leads, 10);
            setStats(s => ({ ...s, sent: s.sent + sentCount, leads: s.leads - sentCount }));
            addLog(`Sent ${sentCount} hyper-personalized outreach sequences.`, 'success');
            break;
          case 'ANALYZE_REPLIES':
            if (Math.random() > 0.7) {
              setStats(s => ({ ...s, replies: s.replies + 1 }));
              addLog(`Positive sentiment detected from a CEO. Reply tagged as "HOT".`, 'success');
              if (Math.random() > 0.5) {
                setStats(s => ({ ...s, bookings: s.bookings + 1 }));
                setCurrentRevenue(r => r + 250); // Demo booking fee
                addLog(`DEMO BOOKED: Client requested meeting for Thursday. Retainer probability: 45%.`, 'success');
              }
            } else {
              addLog(`Processed 3 neutral replies. Automated follow-up scheduled.`, 'info');
            }
            break;
          default:
            addLog("Maintaining server state and optimizing prompt templates...", "info");
        }
      }, 2000);

    } catch (err) {
      addLog("Agent cycle error: Check API availability.", "error");
    }
  }, [isAgentActive, stats, currentRevenue]);

  useEffect(() => {
    let interval: any;
    if (isAgentActive) {
      interval = setInterval(runAgentCycle, 8000);
      addLog("System autonomous mode: INITIALIZED.", "warning");
    } else {
      clearInterval(interval);
      if (logs.length > 0) addLog("System autonomous mode: STANDBY.", "info");
    }
    return () => clearInterval(interval);
  }, [isAgentActive, runAgentCycle]);

  return (
    <div className="flex h-screen overflow-hidden bg-black text-white">
      {/* Sidebar */}
      <aside className="w-64 bg-[#0a0a0a] border-r border-[#1a1a1a] flex flex-col shadow-2xl">
        <div className="p-6">
          <h1 className="text-xl font-extrabold tracking-tighter text-white flex items-center gap-2 italic">
            <ICONS.Zap className="w-6 h-6 text-yellow-500" />
            REVENUE<span className="text-yellow-500">ARCH</span>
          </h1>
          <div className="flex items-center gap-2 mt-2">
            <div className={`w-2 h-2 rounded-full ${isAgentActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
            <span className="text-[10px] text-gray-500 mono font-bold uppercase tracking-widest">
              {isAgentActive ? 'AGENT: ACTIVE' : 'AGENT: STANDBY'}
            </span>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          <NavItem active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<ICONS.Target className="w-4 h-4" />} label="Command" />
          <NavItem active={activeTab === 'strategy'} onClick={() => setActiveTab('strategy')} icon={<ICONS.Dollar className="w-4 h-4" />} label="Strategy" />
          <NavItem active={activeTab === 'leads'} onClick={() => setActiveTab('leads')} icon={<ICONS.Users className="w-4 h-4" />} label="Leads" />
          <NavItem active={activeTab === 'checklist'} onClick={() => setActiveTab('checklist')} icon={<ICONS.Code className="w-4 h-4" />} label="Sprint" />
        </nav>

        <div className="p-4 m-4 rounded-xl bg-gradient-to-br from-[#111] to-black border border-[#222]">
          <button 
            onClick={() => setIsAgentActive(!isAgentActive)}
            className={`w-full py-3 rounded-lg font-black uppercase text-xs tracking-widest transition-all ${
              isAgentActive 
              ? 'bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-500 hover:text-white' 
              : 'bg-yellow-500 text-black hover:bg-yellow-400'
            }`}
          >
            {isAgentActive ? 'Shutdown Agent' : 'Start Agent'}
          </button>
        </div>

        <div className="p-6 border-t border-[#1a1a1a]">
          <div className="flex justify-between items-end mb-2">
            <span className="text-xs text-gray-400 font-bold uppercase">Net Profit</span>
            <span className="text-sm font-bold text-green-500 mono">${currentRevenue.toLocaleString()}</span>
          </div>
          <div className="h-1.5 bg-[#1a1a1a] rounded-full overflow-hidden">
            <div 
              className="h-full bg-green-500 transition-all duration-1000" 
              style={{ width: `${(currentRevenue / REVENUE_GOAL) * 100}%` }}
            />
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-16 border-b border-[#1a1a1a] flex items-center justify-between px-8 bg-[#0a0a0a]">
          <h2 className="text-sm font-bold text-gray-400 uppercase tracking-[0.3em]">
            {activeTab === 'dashboard' && 'Operations Terminal'}
            {activeTab === 'strategy' && 'Profit Logic v2'}
            {activeTab === 'leads' && 'Autonomous Lead Enrichment'}
            {activeTab === 'checklist' && 'Operator Sprint List'}
          </h2>
          <div className="flex items-center gap-6">
            <StatSmall label="LEADS" val={stats.leads} />
            <StatSmall label="OUTREACH" val={stats.sent} />
            <StatSmall label="REPLIES" val={stats.replies} />
            <StatSmall label="BOOKINGS" val={stats.bookings} />
          </div>
        </header>

        <div className="flex-1 overflow-hidden flex">
          <main className="flex-1 overflow-y-auto p-8 custom-scrollbar">
            {activeTab === 'dashboard' && <Dashboard />}
            {activeTab === 'strategy' && <StrategyRoom />}
            {activeTab === 'leads' && <LeadGenerator />}
            {activeTab === 'checklist' && <Checklist />}
          </main>

          {/* Agent Console Panel */}
          <aside className="w-96 border-l border-[#1a1a1a] p-4 bg-[#050505]">
            <AgentConsole logs={logs} isWorking={isAgentActive} />
          </aside>
        </div>
      </div>
    </div>
  );
};

