import React, { useState, useEffect, useCallback } from 'react';
import { ICONS, REVENUE_GOAL } from './constants';
import Dashboard from './components/Dashboard';
import StrategyRoom from './components/StrategyRoom';
import LeadGenerator from './components/LeadGenerator';
import Checklist from './components/Checklist';
import AgentConsole from './components/AgentConsole';
import { RevenueService } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'strategy' | 'leads' | 'checklist'>('dashboard');
  const [currentRevenue, setCurrentRevenue] = useState(1250);
  const [isAgentActive, setIsAgentActive] = useState(false);
  const [logs, setLogs] = useState<any[]>([]);
  const [stats, setStats] = useState({ leads: 142, sent: 89, replies: 4, bookings: 1 });

  // Use a ref to store service to avoid re-instantiation
  const [revService] = useState(() => new RevenueService());

  const addLog = (message: string, type: 'info' | 'success' | 'warning' | 'error' | 'agent' = 'info') => {
    setLogs(prev => [...prev, {
      id: Math.random().toString(36),
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    }].slice(-50));
  };

  const runAgentCycle = useCallback(async () => {
    if (!isAgentActive) return;

    try {
      const decision = await revService.decideNextAction({
        leads: stats.leads,
        emailsSent: stats.sent,
        replies: stats.replies,
        profit: currentRevenue
      });

      addLog(`AGENT_LOGIC: ${decision.reasoning}`, 'agent');
      addLog(decision.logMessage, 'info');

      // Random delay to simulate execution work
      setTimeout(() => {
        switch (decision.action) {
          case 'SCRAPE_LEADS':
            const newLeads = Math.floor(Math.random() * 10) + 2;
            setStats(s => ({ ...s, leads: s.leads + newLeads }));
            addLog(`Captured ${newLeads} high-intent prospects from LinkedIn.`, 'success');
            break;
          case 'SEND_OUTREACH':
            const sentCount = Math.min(stats.leads, 5);
            setStats(s => ({ ...s, sent: s.sent + sentCount, leads: s.leads - sentCount }));
            addLog(`Sequenced ${sentCount} hyper-personalized cold emails.`, 'success');
            break;
          case 'ANALYZE_MARKET':
            addLog("Scanning market trends: Competitor X just raised prices. Opportunity detected.", "warning");
            break;
          default:
            addLog("System in maintenance mode. Optimizing backend indices.", "info");
        }
      }, 3000);

    } catch (err) {
      addLog("API Error in autonomous cycle.", "error");
    }
  }, [isAgentActive, stats, currentRevenue, revService]);

  useEffect(() => {
    let interval: any;
    if (isAgentActive) {
      interval = setInterval(runAgentCycle, 10000);
      addLog("AGENT SYSTEM: ENGAGED.", "warning");
    } else {
      clearInterval(interval);
      if (logs.length > 0) addLog("AGENT SYSTEM: SUSPENDED.", "info");
    }
    return () => clearInterval(interval);
  }, [isAgentActive, runAgentCycle]);

  return (
    <div className="flex h-screen overflow-hidden bg-[#050505] text-white">
      {/* Sidebar */}
      <aside className="w-64 bg-[#0a0a0a] border-r border-[#1a1a1a] flex flex-col shadow-2xl z-20">
        <div className="p-8">
          <h1 className="text-2xl font-black tracking-tighter text-white flex items-center gap-2 italic">
            <ICONS.Zap className="w-7 h-7 text-yellow-500 fill-yellow-500" />
            PROF<span className="text-yellow-500">IT</span>OS
          </h1>
          <div className="flex items-center gap-2 mt-4">
            <div className={`w-2 h-2 rounded-full ${isAgentActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
            <span className="text-[9px] text-gray-500 mono font-bold uppercase tracking-[0.2em]">
              {isAgentActive ? 'MODE: AUTONOMOUS' : 'MODE: MANUAL'}
            </span>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-1 mt-4">
          <NavItem active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<ICONS.Target className="w-4 h-4" />} label="Command Center" />
          <NavItem active={activeTab === 'strategy'} onClick={() => setActiveTab('strategy')} icon={<ICONS.Dollar className="w-4 h-4" />} label="Profit Strategy" />
          <NavItem active={activeTab === 'leads'} onClick={() => setActiveTab('leads')} icon={<ICONS.Users className="w-4 h-4" />} label="Lead Engine" />
          <NavItem active={activeTab === 'checklist'} onClick={() => setActiveTab('checklist')} icon={<ICONS.Code className="w-4 h-4" />} label="Daily Sprint" />
        </nav>

        <div className="p-4 m-4 rounded-2xl bg-gradient-to-br from-[#111] to-black border border-[#222] shadow-inner">
          <button 
            onClick={() => setIsAgentActive(!isAgentActive)}
            className={`w-full py-4 rounded-xl font-black uppercase text-[10px] tracking-[0.2em] transition-all transform active:scale-95 ${
              isAgentActive 
              ? 'bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-600 hover:text-white' 
              : 'bg-yellow-500 text-black hover:bg-yellow-400'
            }`}
          >
            {isAgentActive ? 'Halt Agent' : 'Activate Agent'}
          </button>
        </div>

        <div className="p-8 border-t border-[#1a1a1a]">
          <div className="flex justify-between items-end mb-2">
            <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">NET PROFIT</span>
            <span className="text-sm font-black text-green-500 mono">${currentRevenue.toLocaleString()}</span>
          </div>
          <div className="h-1 bg-[#1a1a1a] rounded-full overflow-hidden">
            <div 
              className="h-full bg-green-500 transition-all duration-1000" 
              style={{ width: `${(currentRevenue / REVENUE_GOAL) * 100}%` }}
            />
          </div>
          <p className="text-[8px] text-gray-600 mt-2 text-center font-bold tracking-widest">ROAD TO $100K (2026)</p>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-20 border-b border-[#1a1a1a] flex items-center justify-between px-10 bg-[#0a0a0a]/50 backdrop-blur-xl">
          <h2 className="text-xs font-black text-gray-400 uppercase tracking-[0.4em] italic">
            {activeTab === 'dashboard' && 'Operations Terminal'}
            {activeTab === 'strategy' && 'The $100k Blueprint'}
            {activeTab === 'leads' && 'Autonomous Enrichment'}
            {activeTab === 'checklist' && 'Execution Sprint'}
          </h2>
          <div className="flex items-center gap-8">
            <StatBox label="LEADS" val={stats.leads} />
            <StatBox label="SENT" val={stats.sent} />
            <StatBox label="REPLIES" val={stats.replies} />
            <StatBox label="MEETINGS" val={stats.bookings} color="text-yellow-500" />
          </div>
        </header>

        <div className="flex-1 overflow-hidden flex">
          <main className="flex-1 overflow-y-auto p-10 custom-scrollbar relative">
            <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-yellow-500/5 to-transparent pointer-events-none" />
            {activeTab === 'dashboard' && <Dashboard />}
            {activeTab === 'strategy' && <StrategyRoom />}
            {activeTab === 'leads' && <LeadGenerator />}
            {activeTab === 'checklist' && <Checklist />}
          </main>

          {/* Right Hand Persistent Agent Console */}
          <aside className="w-[400px] border-l border-[#1a1a1a] p-6 bg-[#030303] hidden xl:flex flex-col">
            <AgentConsole logs={logs} isWorking={isAgentActive} />
            <div className="mt-6 p-4 border border-[#222] rounded-xl bg-black/40">
                <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <span className="w-2 h-2 bg-yellow-500 rounded-full" />
                    Operator Logic
                </h4>
                <p className="text-[11px] text-gray-400 leading-relaxed italic">
                    The agent is currently prioritizing High-Intent SEO Agency founders with >$1M ARR. 
                    Personalization strategy: "Outcome-Based Automation".
                </p>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

