import { GoogleGenAI } from "@google/genai";

export class RevenueService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  /**
   * Generates hyper-personalized outreach based on prospect data.
   */
  async generateOutreach(prospect: { company: string, contact: string, pain: string }) {
    const prompt = `
      Act as a world-class B2B Sales Engineer.
      Company: ${prospect.company}
      Contact: ${prospect.contact}
      Identified Pain Point: ${prospect.pain}

      Objective: Write a short, "punchy" cold email (max 80 words) proposing an AI-Agent automation that solves their specific pain.
      Constraints:
      1. No fluff.
      2. No "I hope you're well".
      3. Focus on ROI and time saved.
      4. End with a low-friction CTA (e.g., "Worth a 2-min chat?").
      5. Tone: Technical peer, high status, direct.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          temperature: 0.8,
          topP: 0.95,
        }
      });
      return response.text || "Failed to generate outreach.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Critical failure in content generation loop.";
    }
  }

  /**
   * Simulates the AI "executing" a complex strategic task from the checklist.
   */
  async executeTask(taskLabel: string) {
    const prompt = `
      You are an autonomous AI Agent performing this specific business task: "${taskLabel}".
      Describe in 2 technical sentences the complex sub-steps you just performed to finish this task perfectly.
      Maintain a cold, efficient, profit-focused tone.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });
      return response.text || "Execution complete. Efficiency optimized.";
    } catch (e) {
      return "Task completed via fallback protocol.";
    }
  }

  /**
   * Autonomous Agent decision-making logic.
   */
  async decideNextAction(context: { leads: number, emailsSent: number, replies: number, profit: number }) {
    const prompt = `
      Act as RevenueArchitect-AI Autonomous Operator.
      Analyze the current startup state:
      - Leads in CRM: ${context.leads}
      - Outreach volume: ${context.emailsSent}
      - Positive Responses: ${context.replies}
      - Cumulative Profit: $${context.profit}

      Output a JSON object:
      {
        "action": "SCRAPE_LEADS" | "GENERATE_COPY" | "SEND_OUTREACH" | "ANALYZE_MARKET",
        "reasoning": "A one-sentence aggressive business rationale.",
        "logMessage": "A technical terminal-style message for the console."
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
        }
      });
      return JSON.parse(response.text || "{}");
    } catch (e) {
      return { 
        action: "SCRAPE_LEADS", 
        reasoning: "Lead pipeline is low. Prioritizing acquisition.", 
        logMessage: "Initializing LinkedIn scraper module v4.1..." 
      };
    }
  }
}

