    setLogs(prev => [...prev, {
      id: Math.random().toString(36),
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    }].slice(-50));
  };

  const toggleTask = (id: number) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, done: !t.done } : t));
  };

  const runAgentCycle = useCallback(async () => {
    if (!isAgentActive) return;

    // 1. Check for pending tasks to automate
    const nextTask = tasks.find(t => !t.done);

    if (nextTask) {
      addLog(`AUTONOMOUS SPRINT: Attempting task "${nextTask.label}"...`, 'agent');
      const executionLog = await revService.executeTask(nextTask.label);
      addLog(`EXECUTION REPORT: ${executionLog}`, 'success');
      toggleTask(nextTask.id);
      addLog(`TASK COMPLETE: ${nextTask.label} marked as executed.`, 'success');
    }

    // 2. Run standard revenue generation logic
    try {
      const decision = await revService.decideNextAction({
        leads: stats.leads,
        emailsSent: stats.sent,
        replies: stats.replies,
        profit: currentRevenue
      });
      addLog(`AGENT_LOGIC: ${decision.reasoning}`, 'agent');
