            <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${isAgentActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
                <span className="text-[9px] text-gray-500 mono font-bold uppercase tracking-[0.2em]">
                {isAgentActive ? 'MODE: AUTONOMOUS' : 'MODE: MANUAL'}
                </span>
            </div>
            {isAgentActive && (
                <span className="text-[8px] text-yellow-500/50 uppercase font-black tracking-widest">NEXT SYNC: {nextRun}s</span>
            )}
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-1 mt-4">
          <NavItem active={activeTab === 'dashboard'} onClick={() => { setActiveTab('dashboard'); setIsMobileMenuOpen(false); }} icon={<ICONS.Target className="w-4 h-4" />} label="Command Center" />
          <NavItem active={activeTab === 'strategy'} onClick={() => { setActiveTab('strategy'); setIsMobileMenuOpen(false); }} icon={<ICONS.Dollar className="w-4 h-4" />} label="Profit Strategy" />
          <NavItem active={activeTab === 'leads'} onClick={() => { setActiveTab('leads'); setIsMobileMenuOpen(false); }} icon={<ICONS.Users className="w-4 h-4" />} label="Lead Engine" />
          <NavItem active={activeTab === 'checklist'} onClick={() => { setActiveTab('checklist'); setIsMobileMenuOpen(false); }} icon={<ICONS.Code className="w-4 h-4" />} label="Daily Sprint" />
        </nav>

        <div className="p-4 m-4 rounded-2xl bg-[#111] border border-[#222]">
          <button 
            onClick={() => { setIsAgentActive(!isAgentActive); setIsMobileMenuOpen(false); }}
            className={`w-full py-4 rounded-xl font-black uppercase text-[10px] tracking-[0.2em] transition-all transform active:scale-95 ${
              isAgentActive ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-yellow-500 text-black hover:bg-yellow-400'
            }`}
          >
            {isAgentActive ? 'Halt Automation' : 'Activate Automation'}
          </button>
        </div>

        <div className="p-8 border-t border-[#1a1a1a]">
          <div className="flex justify-between items-end mb-2">
            <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">NET PROFIT</span>
            <span className="text-sm font-black text-green-500 mono">${currentRevenue.toLocaleString()}</span>
          </div>
          <div className="h-1 bg-[#1a1a1a] rounded-full overflow-hidden">
            <div className="h-full bg-green-500 transition-all duration-1000" style={{ width: `${(currentRevenue / REVENUE_GOAL) * 100}%` }} />
          </div>
          <button 
            onClick={() => { localStorage.removeItem('ra_auth'); window.location.reload(); }}
            className="text-[8px] text-gray-700 mt-4 block w-full text-center hover:text-white uppercase tracking-widest"
          >
            Termination Protocol (Logout)
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-16 lg:h-20 border-b border-[#1a1a1a] flex items-center justify-between px-6 lg:px-10 bg-[#0a0a0a]/50 backdrop-blur-xl shrink-0">
