import React, { useState, useEffect, useCallback } from 'react';
import { ICONS, REVENUE_GOAL } from './constants';
import Dashboard from './components/Dashboard';
import StrategyRoom from './components/StrategyRoom';
import LeadGenerator from './components/LeadGenerator';
import Checklist from './components/Checklist';
import AgentConsole from './components/AgentConsole';
import Login from './components/Login';
import { RevenueService } from './services/geminiService';

const INITIAL_TASKS = [
  { id: 1, label: 'Identify 50 High-Ticket Agencies on LinkedIn', cat: 'Lead Generation', done: false },
  { id: 2, label: 'Enrich 50 Leads with Pain Point Data (Job Ads/Case Studies)', cat: 'Lead Generation', done: false },
  { id: 3, label: 'Send 20 Hyper-Personalized Emails via Gemini', cat: 'Sales Outreach', done: false },
  { id: 4, label: 'Follow up on previous 5-day replies', cat: 'Sales Outreach', done: false },
  { id: 5, label: 'Optimize Qualification Agent Prompt based on rejections', cat: 'Agent Building', done: false },
  { id: 6, label: 'Audit conversion metrics for Daily Log', cat: 'Strategy & Analysis', done: false },
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'strategy' | 'leads' | 'checklist'>('dashboard');
  const [currentRevenue, setCurrentRevenue] = useState(1250);
  const [isAgentActive, setIsAgentActive] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isTerminalExpanded, setIsTerminalExpanded] = useState(false);
  const [logs, setLogs] = useState<any[]>([]);
  const [stats, setStats] = useState({ leads: 142, sent: 89, replies: 4, bookings: 1 });
  const [tasks, setTasks] = useState(INITIAL_TASKS);
  const [nextRun, setNextRun] = useState(30);
  const [isThinking, setIsThinking] = useState(false);

  const [revService] = useState(() => new RevenueService());

  useEffect(() => {
    const auth = localStorage.getItem('ra_auth');
    if (auth === 'true') setIsAuthenticated(true);
  }, []);

  const addLog = (message: string, type: 'info' | 'success' | 'warning' | 'error' | 'agent' | 'strategy' = 'info') => {
    setLogs(prev => [...prev, {
      id: Math.random().toString(36),
      timestamp: new Date().toLocaleTimeString('en-GB', { hour12: false }),
      message,
      type
    }].slice(-100));
  };

  const toggleTask = (id: number) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, done: true } : t));
  };

  const runAgentCycle = useCallback(async () => {
    if (!isAgentActive) return;

    setIsThinking(true);
    addLog("AGENT ONLINE: FULL SYSTEM AUTOMATION ENGAGED.", "info");

    // Automation Phase 1: Checklist Task Execution
    const nextTask = tasks.find(t => !t.done);
    if (nextTask) {
      addLog(`AUTONOMOUS_EXEC: Initiating "${nextTask.label}"...`, 'agent');
      const executionDetails = await revService.executeTask(nextTask.label);

      // Delay to simulate processing
      await new Promise(r => setTimeout(r, 2000));

      addLog(`RESULT: ${executionDetails}`, 'info');
      toggleTask(nextTask.id);
      addLog(`SPRINT UPDATE: Task "${nextTask.label}" completed autonomously.`, 'info');
      addLog("AGENT ONLINE: FULL SYSTEM AUTOMATION ENGAGED.", "info");
    }

    // Automation Phase 2: Revenue & Strategy Logic
    try {
      const context = { leads: stats.leads, emailsSent: stats.sent, replies: stats.replies, profit: currentRevenue };
      const decision = await revService.decideNextAction(context);

      addLog(`${decision.reasoning}`, 'strategy');
      addLog(`${decision.logMessage}`, 'info');

      if (decision.action === 'SCRAPE_LEADS') {
        const newLeads = Math.floor(Math.random() * 10) + 5;
        setStats(s => ({ ...s, leads: s.leads + newLeads }));
        addLog(`Pipeline enriched: +${newLeads} high-intent prospects.`, 'success');
      } else if (decision.action === 'SEND_OUTREACH') {
        const sentCount = Math.min(stats.leads, 20);
        setStats(s => ({ ...s, sent: s.sent + sentCount, leads: Math.max(0, stats.leads - sentCount) }));
        addLog(`Automated Outreach: ${sentCount} sequences deployed.`, 'success');
      }

      addLog("AGENT ONLINE: FULL SYSTEM AUTOMATION ENGAGED.", "info");
    } catch (err) {
      addLog("SYSTEM ERROR: UNABLE TO PROCESS AI STRATEGY NODE.", "error");
    } finally {
      setIsThinking(false);
      setNextRun(30);
    }
  }, [isAgentActive, stats, currentRevenue, revService, tasks]);

  useEffect(() => {
    let interval: any;
    if (isAgentActive) {
      setIsTerminalExpanded(true); // Automatically expand terminal when automation starts
      interval = setInterval(() => {
        setNextRun(r => {
          if (r <= 1) {
            runAgentCycle();
            return 30;
          }
          return r - 1;
        });
      }, 1000);
    } else {
      clearInterval(interval);
      setNextRun(30);
    }
    return () => clearInterval(interval);
  }, [isAgentActive, runAgentCycle]);

  if (!isAuthenticated) return <Login onAuthenticated={() => setIsAuthenticated(true)} />;

  return (
    <div className="flex h-screen overflow-hidden bg-[#050505] text-white">
      {/* Permanent Sidebar for Desktop */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-[#0a0a0a] border-r border-[#1a1a1a] flex flex-col transition-transform duration-300
        lg:translate-x-0 lg:static shrink-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-8">
          <h1 className="text-2xl font-black tracking-tighter text-white flex items-center gap-2 italic">
            <ICONS.Zap className="w-8 h-8 text-yellow-500 fill-yellow-500" />
            PROF<span className="text-yellow-500">IT</span>OS
          </h1>

          <div className="mt-8 space-y-1">
            <NavItem active={activeTab === 'dashboard'} onClick={() => { setActiveTab('dashboard'); setIsMobileMenuOpen(false); }} icon={<ICONS.Target className="w-5 h-5" />} label="Command Center" />
            <NavItem active={activeTab === 'strategy'} onClick={() => { setActiveTab('strategy'); setIsMobileMenuOpen(false); }} icon={<ICONS.Dollar className="w-5 h-5" />} label="Strategy Room" />
            <NavItem active={activeTab === 'leads'} onClick={() => { setActiveTab('leads'); setIsMobileMenuOpen(false); }} icon={<ICONS.Users className="w-5 h-5" />} label="Lead Engine" />
            <NavItem active={activeTab === 'checklist'} onClick={() => { setActiveTab('checklist'); setIsMobileMenuOpen(false); }} icon={<ICONS.Code className="w-5 h-5" />} label="Daily Sprints" />
          </div>
        </div>

        <div className="mt-auto p-6 space-y-4">
           <div className="bg-[#111] p-4 rounded-2xl border border-[#222]">
              <div className="flex justify-between items-center mb-2">
                <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Automation</span>
                <div className={`w-2 h-2 rounded-full ${isAgentActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
              </div>
              <button 
                onClick={() => setIsAgentActive(!isAgentActive)}
                className={`w-full py-3 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all ${
                  isAgentActive ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-yellow-500 text-black'
                }`}
              >
                {isAgentActive ? 'Stop Agent' : 'Start Agent'}
              </button>
           </div>

           <div className="p-2">
              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest mb-2">
                 <span className="text-gray-500">Profit Progress</span>
                 <span className="text-green-500">${currentRevenue}</span>
              </div>
              <div className="h-1 bg-[#222] rounded-full overflow-hidden">
                 <div className="h-full bg-green-500 transition-all duration-1000" style={{ width: `${(currentRevenue / REVENUE_GOAL) * 100}%` }} />
              </div>
           </div>

           <button onClick={() => { localStorage.removeItem('ra_auth'); window.location.reload(); }} className="w-full text-[9px] text-gray-700 uppercase font-black hover:text-white transition-colors">Logout Session</button>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col relative overflow-hidden">
        <header className="h-20 border-b border-[#1a1a1a] flex items-center justify-between px-10 bg-[#0a0a0a]/50 backdrop-blur-xl z-20">
           <div className="flex items-center gap-4">
              <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden text-gray-400">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
              </button>
              <h2 className="text-xs font-black text-gray-400 uppercase tracking-[0.4em] italic truncate">
                {activeTab.toUpperCase()} TERMINAL
              </h2>
           </div>
           <div className="flex items-center gap-8">
              <StatBox label="PIPELINE" val={stats.leads} color="text-blue-400" />
