import React, { useEffect, useRef } from 'react';

interface Log {
  id: string;
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error' | 'agent' | 'strategy';
}

interface AgentConsoleProps {
  logs: Log[];
  isWorking: boolean;
}

const AgentConsole: React.FC<AgentConsoleProps> = ({ logs, isWorking }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs, isWorking]);

  const renderLogMessage = (log: Log) => {
    if (log.type === 'agent') {
      return (
        <span className="text-blue-400 font-bold">
          <span className="mr-2">🤖</span>{log.message}
        </span>
      );
    }
    if (log.type === 'strategy') {
      return (
        <span className="text-yellow-500 font-bold">
          <span className="mr-2">🤖</span>STRATEGY_ENGINE: <span className="text-gray-300 font-normal">{log.message}</span>
        </span>
      );
    }
    if (log.type === 'success') {
      return <span className="text-green-500">{log.message}</span>;
    }
    if (log.type === 'error') {
      return <span className="text-red-500 font-bold">CRITICAL_ERR: {log.message}</span>;
    }

    // Default info/log style
    const isOperator = log.message.startsWith('[OPERATOR]') || log.message.includes('[REVENUE_ARCHITECT]');
    return (
      <span className={isOperator ? "text-yellow-500/80 font-bold" : "text-gray-400"}>
        <span className="opacity-30 mr-2">{'>'}</span>{log.message}
      </span>
    );
  };

  return (
    <div className="h-full bg-black/95 p-4 mono text-[11px] overflow-y-auto space-y-1 custom-scrollbar scroll-smooth">
      {logs.length === 0 && (
        <div className="text-gray-800 italic uppercase tracking-widest mt-4 text-center">
          System idle. Initiate automation sequence for live logs.
