        <div key={log.id} className="flex gap-3 leading-relaxed hover:bg-white/5 px-2 py-0.5 rounded transition-colors group">
          <span className="text-gray-700 shrink-0 font-bold">[{log.timestamp}]</span>
          <div className="flex-1">
            {renderLogMessage(log)}
          </div>
        </div>
      ))}
      {isWorking && (
        <div className="flex gap-3 text-yellow-500/50 animate-pulse px-2 py-0.5">
          <span className="shrink-0">[{new Date().toLocaleTimeString('en-GB', { hour12: false })}]</span>
          <span className="italic font-bold">Agent is thinking...</span>
        </div>
      )}
    </div>
  );
};

