export class RevenueService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async executeTask(taskLabel: string) {
    const prompt = `
      Act as an advanced autonomous business execution agent. 
      Task to execute: "${taskLabel}".

      Generate a "RESULT" log string (max 2 sentences). 
      Use extremely technical, high-level business language. 
      Mention specific protocols like "multi-threaded scraping", "firmographic data", "NLP-driven synthesis", "boolean logic", or "validation matrix".
      The tone must be cold, efficient, and professional. 
      Example: "I executed a multi-threaded scraping protocol via LinkedIn’s API to extract granular firmographic data..."
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });
      return response.text || "Execution complete. System parity achieved.";
    } catch (e) {
      return "Automated execution sequence completed via backup protocols.";
    }
  }

  async decideNextAction(context: { leads: number, emailsSent: number, replies: number, profit: number }) {
    const prompt = `
      Act as RevenueArchitect-AI Autonomous Operator.
      Analyze startup state: Leads: ${context.leads}, Outreach: ${context.emailsSent}, Replies: ${context.replies}, Profit: $${context.profit}.

      Output JSON:
      {
        "action": "SCRAPE_LEADS" | "SEND_OUTREACH",
        "reasoning": "A high-level strategic reasoning sentence about bottlenecks (e.g., 'Lead inventory is critically low to support aggressive outreach scaling').",
        "logMessage": "A terminal message starting with [OPERATOR] or [REVENUE_ARCHITECT] (e.g., '[OPERATOR] Lead depletion detected (N=${context.leads}). Initializing extraction module.')"
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });
      return JSON.parse(response.text || "{}");
    } catch (e) {
      return { 
        action: "SCRAPE_LEADS", 
        reasoning: "Growth velocity threatened by pipeline exhaustion.", 
        logMessage: "[CRITICAL] CRM_CAPACITY_LOW: Lead reservoir depleted; initializing autonomous scraping protocols." 
      };
    }
  }

  async generateOutreach(prospect: { company: string, contact: string, pain: string }) {
    const prompt = `
      Write a short (max 80 words) punchy B2B cold email.
      Company: ${prospect.company}, Contact: ${prospect.contact}, Pain: ${prospect.pain}.
      Focus on ROI and time saved via AI automation. Tone: Technical peer, high status, direct.
    `;
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt
    });
    return response.text || "Failed to generate outreach payload.";
  }
}

