           <button onClick={() => { localStorage.removeItem('ra_auth'); window.location.reload(); }} className="w-full text-[9px] text-gray-700 uppercase font-black hover:text-white transition-colors">Terminate Session</button>
        </div>
      </aside>

      {/* Workspace */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-[#050505]">
        <header className="h-20 border-b border-[#1a1a1a] flex items-center justify-between px-10 bg-[#0a0a0a]/50 backdrop-blur-xl z-20">
